import{_ as t,a}from"./chunks/添加渠道.o1VHzHEI.js";import{_ as n,o as s,c as i,a2 as o}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"Hugging Face Channel சேர்க்கவும்","description":"","frontmatter":{},"headers":[],"relativePath":"ta/upload/huggingface.md","filePath":"ta/upload/huggingface.md","lastUpdated":1781962217000}'),r={name:"ta/upload/huggingface.md"};function d(c,e,l,p,g,h){return s(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="hugging-face-channel-சேர்க்கவும்" tabindex="-1">Hugging Face Channel சேர்க்கவும் <a class="header-anchor" href="#hugging-face-channel-சேர்க்கவும்" aria-label="Permalink to &quot;Hugging Face Channel சேர்க்கவும்&quot;">​</a></h1><h2 id="தொடங்குவதற்கு-முன்-தேவையானவை" tabindex="-1">தொடங்குவதற்கு முன் தேவையானவை <a class="header-anchor" href="#தொடங்குவதற்கு-முன்-தேவையானவை" aria-label="Permalink to &quot;தொடங்குவதற்கு முன் தேவையானவை&quot;">​</a></h2><p>மூன்று விஷயங்கள் போதும்:</p><table tabindex="0"><thead><tr><th>தேவை</th><th>பயன்பாடு</th></tr></thead><tbody><tr><td>Hugging Face account</td><td>access token உருவாக்கவும் repository own செய்யவும்</td></tr><tr><td>Hugging Face User Access Token</td><td>ImgBed Hugging Face API அணுக, repositories உருவாக்க, files upload செய்ய</td></tr><tr><td>Repository name</td><td>repository name மட்டும் கொடுக்கலாம், உதா. <code>image</code></td></tr></tbody></table><h2 id="setup-steps" tabindex="-1">Setup Steps <a class="header-anchor" href="#setup-steps" aria-label="Permalink to &quot;Setup Steps&quot;">​</a></h2><h3 id="step-1-hugging-face-ல்-sign-in-செய்து-access-token-உருவாக்கவும்" tabindex="-1">Step 1: Hugging Face-ல் Sign in செய்து Access Token உருவாக்கவும் <a class="header-anchor" href="#step-1-hugging-face-ல்-sign-in-செய்து-access-token-உருவாக்கவும்" aria-label="Permalink to &quot;Step 1: Hugging Face-ல் Sign in செய்து Access Token உருவாக்கவும்&quot;">​</a></h3><ol><li>Hugging Face-ல் sign in செய்யவும்.</li><li>மேல் வலது மூலையில் avatar கிளிக் செய்து <code>Settings</code> திறக்கவும்.</li><li>left sidebar-ல் <code>Access Tokens</code> திறக்கவும்.</li><li>புதிய token உருவாக்கவும்.</li><li>அடையாளம் காண எளிதான பெயர் கொடுக்கவும்.</li><li><code>write</code> permission தேர்வு செய்யவும்.</li><li>token உருவானதும் உடனே copy செய்து சேமிக்கவும்.</li></ol><p><img src="'+t+'" alt="Create a token" loading="lazy"></p><h2 id="step-2-imgbed-ல்-hugging-face-channel-நிரப்பவும்" tabindex="-1">Step 2: ImgBed-ல் Hugging Face Channel நிரப்பவும் <a class="header-anchor" href="#step-2-imgbed-ல்-hugging-face-channel-நிரப்பவும்" aria-label="Permalink to &quot;Step 2: ImgBed-ல் Hugging Face Channel நிரப்பவும்&quot;">​</a></h2><p>Upload Settings-ல் <code>Hugging Face</code> தேர்வு செய்த பிறகு:</p><table tabindex="0"><thead><tr><th>UI Field</th><th>What to Enter</th></tr></thead><tbody><tr><td>Channel name</td><td>உங்கள் பெயர், உதா. <code>hf-primary</code>.</td></tr><tr><td>Repository name</td><td>short repo name <code>image</code>, அல்லது full path <code>username/image</code>.</td></tr><tr><td>Access Token</td><td>இப்போது உருவாக்கிய Hugging Face User Access Token.</td></tr><tr><td>Private repository</td><td>தேவைக்கேற்ப on/off.</td></tr><tr><td>Remark</td><td>optional, உதா. <code>Primary upload channel</code>.</td></tr></tbody></table><p><img src="'+a+`" alt="Add the channel" loading="lazy"></p><h2 id="step-3-channel-save-செய்யவும்" tabindex="-1">Step 3: Channel Save செய்யவும் <a class="header-anchor" href="#step-3-channel-save-செய்யவும்" aria-label="Permalink to &quot;Step 3: Channel Save செய்யவும்&quot;">​</a></h2><p>fields நிரப்பிய பிறகு Save கிளிக் செய்யவும்.</p><p>system இதை தானாக கையாளும்:</p><table tabindex="0"><thead><tr><th>System Behavior</th><th>Description</th></tr></thead><tbody><tr><td>Short repository name</td><td>ImgBed current Hugging Face account கண்டறிந்து full repository path ஆக expand செய்கிறது.</td></tr><tr><td>Full repository path</td><td><code>username/repository</code> path-ஐ நீங்கள் உள்ளிட்டபடியே பயன்படுத்தும்.</td></tr><tr><td>Repository check</td><td>current personal account path என்றால் repository இல்லாதபோது create செய்ய முயலும். full path manual என்றால் அதையே பயன்படுத்தும்.</td></tr><tr><td>Repository type</td><td>இந்த channel <code>dataset</code> repository பயன்படுத்தும்.</td></tr><tr><td>Public/private state</td><td>repository visibility current switch படி synchronized ஆகும்.</td></tr></tbody></table><h2 id="quick-checklist" tabindex="-1">Quick Checklist <a class="header-anchor" href="#quick-checklist" aria-label="Permalink to &quot;Quick Checklist&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Hugging Face-ல் sign in செய்யவும்</span></span>
<span class="line"><span>-&gt; Access Token உருவாக்கவும்</span></span>
<span class="line"><span>-&gt; write permission தேர்வு செய்யவும்</span></span>
<span class="line"><span>-&gt; ImgBed-க்கு திரும்பி token மற்றும் repository name நிரப்பவும்</span></span>
<span class="line"><span>-&gt; Save</span></span>
<span class="line"><span>-&gt; repo name மட்டும் இருந்தால் ImgBed current username சேர்க்கும்</span></span>
<span class="line"><span>-&gt; username/repo இருந்தால் அதையே பயன்படுத்தும்</span></span>
<span class="line"><span>-&gt; ImgBed dataset repository check அல்லது create செய்யும்</span></span>
<span class="line"><span>-&gt; test image upload செய்யவும்</span></span></code></pre></div>`,18)])])}const k=n(r,[["render",d]]);export{b as __pageData,k as default};
